import pandas as pd
import numpy as np

# 仅复用已暂存的中间结果，组装必需输出变量；不重新查询、不重新解析实体。
def _to_float(x):
    if isinstance(x, (pd.Series, pd.Index, np.ndarray, list, tuple)):
        x = list(x)[0] if len(x) else np.nan
    if pd.isna(x):
        raise ValueError("必需均值为空，无法设置输出变量。")
    return float(x)

def _norm(s):
    return str(s).strip().lower().replace(" ", "").replace("_", "")

def _find_col(df, candidates):
    if df is None or not hasattr(df, "columns"):
        return None
    cmap = {_norm(c): c for c in df.columns}
    for cand in candidates:
        if _norm(cand) in cmap:
            return cmap[_norm(cand)]
    for c in df.columns:
        nc = _norm(c)
        if any(_norm(cand) in nc for cand in candidates):
            return c
    return None

def _extract_station_id_from_resolved(df):
    if df is None or not hasattr(df, "empty") or df.empty:
        return None
    id_col = _find_col(df, ["id", "station_id", "air_quality_station_id"])
    if id_col is None:
        return None
    vals = pd.to_numeric(df[id_col], errors="coerce").dropna().unique()
    return int(vals[0]) if len(vals) else None

def _extract_from_summary(summary_df, station_id=None, station_name_keywords=None):
    if summary_df is None or not hasattr(summary_df, "empty") or summary_df.empty:
        return None, None
    df = summary_df.copy()
    id_col = _find_col(df, ["station_id", "id", "air_quality_station_id"])
    name_col2 = _find_col(df, ["station_name", "name", "站点", "station"])
    pm_col2 = _find_col(df, ["mean_pm2_5", "mean_pm25", "avg_pm2_5", "avg_pm25", "pm2_5_mean", "pm25_mean", "pm2_5", "pm25"])
    aqi_col2 = _find_col(df, ["mean_aqi", "avg_aqi", "aqi_mean", "aqi"])
    if station_id is not None and id_col is not None:
        sub = df[pd.to_numeric(df[id_col], errors="coerce") == int(station_id)]
    elif station_name_keywords and name_col2 is not None:
        pat = "|".join(station_name_keywords)
        sub = df[df[name_col2].astype(str).str.contains(pat, case=False, na=False, regex=True)]
    else:
        sub = df
    if sub.empty or pm_col2 is None or aqi_col2 is None:
        return None, None
    return _to_float(sub.iloc[0][pm_col2]), _to_float(sub.iloc[0][aqi_col2])

def _extract_from_daily_dict(dct, station_id=None, station_name_keywords=None):
    if not isinstance(dct, dict):
        return None, None
    candidates = []
    if station_id is not None:
        for k in [station_id, str(station_id)]:
            if k in dct:
                candidates.append(dct[k])
    if station_name_keywords:
        for k, val in dct.items():
            if any(kw.lower() in str(k).lower() for kw in station_name_keywords):
                candidates.append(val)
    for val in candidates:
        if isinstance(val, dict):
            pm_key = next((k for k in val.keys() if _norm(k) in [_norm(x) for x in ["mean_pm2_5","mean_pm25","pm2_5","pm25","avg_pm2_5","avg_pm25"]]), None)
            aqi_key = next((k for k in val.keys() if _norm(k) in [_norm(x) for x in ["mean_aqi","aqi","avg_aqi"]]), None)
            if pm_key is not None and aqi_key is not None:
                return _to_float(val[pm_key]), _to_float(val[aqi_key])
        elif isinstance(val, (list, tuple)) and len(val) >= 2:
            return _to_float(val[0]), _to_float(val[1])
    return None, None

