import pandas as pd
import numpy as np
import math

def valid_num(x):
    try:
        return x is not None and not pd.isna(x) and math.isfinite(float(x))
    except Exception:
        return False

def as_float_or_none(x):
    if isinstance(x, (pd.Series, pd.Index, np.ndarray, list, tuple)):
        for y in list(x):
            if valid_num(y):
                return float(y)
        return None
    return float(x) if valid_num(x) else None

def norm_col(s):
    return str(s).lower().replace(" ", "").replace("_", "").replace(".", "").replace("-", "")

def find_col(df, patterns):
    if df is None or not hasattr(df, "columns"):
        return None
    pats = [norm_col(p) for p in patterns]
    for c in df.columns:
        nc = norm_col(c)
        if any(p == nc or p in nc for p in pats):
            return c
    return None

def station_id_from_resolved(df):
    if df is None or not hasattr(df, "empty") or df.empty:
        return None
    c = find_col(df, ["station_id", "air_quality_station_id", "id"])
    if c is None:
        return None
    vals = pd.to_numeric(df[c], errors="coerce").dropna().astype(int).unique()
    return int(vals[0]) if len(vals) else None

