def scan_daily_dict_for_station(dct, sid=None, name_terms=None):
    if not isinstance(dct, dict):
        return None, None
    name_terms = name_terms or []
    keys = []
    if sid is not None:
        keys.extend([sid, str(sid)])
    keys.extend([k for k in dct.keys() if any(t.lower() in str(k).lower() for t in name_terms)])
    keys.extend(list(dct.keys()))
    seen = set()
    for k in keys:
        sk = str(k)
        if sk in seen or k not in dct:
            continue
        seen.add(sk)
        v = dct[k]
        if isinstance(v, dict):
            pm_key = None
            aqi_key = None
            for kk in v.keys():
                nk = norm_col(kk)
                if pm_key is None and any(p in nk for p in ["meanpm25", "avgpm25", "pm25mean", "pm25", "meanpm25", "pm25"]):
                    pm_key = kk
                if aqi_key is None and any(p in nk for p in ["meanaqi", "avgaqi", "aqimean", "aqi"]):
                    aqi_key = kk
            pm = as_float_or_none(v.get(pm_key)) if pm_key is not None else None
            aq = as_float_or_none(v.get(aqi_key)) if aqi_key is not None else None
            if pm is not None and aq is not None:
                return pm, aq
        elif isinstance(v, (list, tuple)) and len(v) >= 2:
            pm, aq = as_float_or_none(v[0]), as_float_or_none(v[1])
            if pm is not None and aq is not None:
                return pm, aq
    return None, None

def extract_from_summary(df, sid=None, name_terms=None):
    if df is None or not hasattr(df, "empty") or df.empty:
        return None, None
    name_terms = name_terms or []
    idc = find_col(df, ["station_id", "air_quality_station_id", "id"])
    namec = find_col(df, ["station_name", "name", "站点", "station"])
    pmc = find_col(df, ["mean_pm2_5", "mean_pm25", "avg_pm2_5", "avg_pm25", "pm2_5_mean", "pm25_mean", "pm2_5", "pm25"])
    aqic = find_col(df, ["mean_aqi", "avg_aqi", "aqi_mean", "aqi"])
    if pmc is None or aqic is None:
        return None, None
    cand = df.copy()
    subsets = []
    if sid is not None and idc is not None:
        subsets.append(cand[pd.to_numeric(cand[idc], errors="coerce") == int(sid)])
    if namec is not None and name_terms:
        pat = "|".join(name_terms)
        subsets.append(cand[cand[namec].astype(str).str.contains(pat, case=False, na=False, regex=True)])
    subsets.append(cand)
    for sub in subsets:
        if sub is None or sub.empty:
            continue
        for _, r in sub.iterrows():
            pm, aq = as_float_or_none(r[pmc]), as_float_or_none(r[aqic])
            if pm is not None and aq is not None:
                return pm, aq
    return None, None

def extract_from_obs(df, sid=None, name_terms=None):
    if df is None or not hasattr(df, "empty") or df.empty:
        return None, None
    idc = find_col(df, ["station_id", "air_quality_station_id", "id"])
    namec = find_col(df, ["station_name", "name", "站点", "station"])
    pmc = find_col(df, ["pm2_5", "pm25"])
    aqic = find_col(df, ["aqi"])
    if pmc is None or aqic is None:
        return None, None
    sub = df.copy()
    if idc is not None and sid is not None:
        tmp = sub[pd.to_numeric(sub[idc], errors="coerce") == int(sid)]
        if not tmp.empty:
            sub = tmp
    elif namec is not None and name_terms:
        pat = "|".join(name_terms)
        tmp = sub[sub[namec].astype(str).str.contains(pat, case=False, na=False, regex=True)]
        if not tmp.empty:
            sub = tmp
    pm = pd.to_numeric(sub[pmc], errors="coerce").mean()
    aq = pd.to_numeric(sub[aqic], errors="coerce").mean()
    return (float(pm), float(aq)) if valid_num(pm) and valid_num(aq) else (None, None)

