def cn_enterprise_interpretation(assessment):
    if not isinstance(assessment, dict) or not assessment:
        return "已完成企业、站点与风场联动检查；现有暂存结果未给出可量化归因结论，因此不将企业影响判定为确定来源。"
    parts = []
    for k, v in assessment.items():
        if isinstance(v, (str, int, float, bool)) and not pd.isna(v):
            parts.append(f"{k}={v}")
        elif isinstance(v, dict):
            inner = []
            for kk, vv in list(v.items())[:6]:
                if isinstance(vv, (str, int, float, bool)) and not pd.isna(vv):
                    inner.append(f"{kk}={vv}")
            if inner:
                parts.append(f"{k}（{'，'.join(inner)}）")
        elif isinstance(v, (list, tuple)) and len(v):
            compact = "，".join(str(x) for x in v[:4])
            parts.append(f"{k}（{compact}）")
    return "基于已暂存的企业排放、站点响应和风场空间联动评估，企业影响解释为：" + ("；".join(parts) if parts else "未形成确定的企业影响证据链，建议作为线索继续核查。")

